alert = inputs.get('alert', {})

suspicious_domain = alert.get('domain', '')
legitimate_domains = alert.get('legitimate_domains', ['organization.com'])

def levenshtein_distance(s1, s2):
    if len(s1) < len(s2):
        return levenshtein_distance(s2, s1)
    if len(s2) == 0:
        return len(s1)
    prev_row = range(len(s2) + 1)
    for i, c1 in enumerate(s1):
        curr_row = [i + 1]
        for j, c2 in enumerate(s2):
            insertions = prev_row[j + 1] + 1
            deletions = curr_row[j] + 1
            substitutions = prev_row[j] + (c1 != c2)
            curr_row.append(min(insertions, deletions, substitutions))
        prev_row = curr_row
    return prev_row[-1]

similarities = []
for legit in legitimate_domains:
    legit_base = legit.split('.')[0]
    suspicious_base = suspicious_domain.split('.')[0]
    distance = levenshtein_distance(legit_base, suspicious_base)
    similarity = max(0, 1 - distance / max(len(legit_base), len(suspicious_base))) * 100
    similarities.append({'legitimate': legit, 'similarity': round(similarity, 1), 'distance': distance})

best_match = max(similarities, key=lambda x: x['similarity'])

result = {
    'suspicious_domain': suspicious_domain,
    'best_match': best_match,
    'similarity_score': best_match['similarity'],
    'is_likely_impersonation': best_match['similarity'] >= 60,
    'all_comparisons': similarities
}

